    uint32_t aLength = totalLength / normalized_elems;
    uint32_t rLength = normalized_elems;

    float epsilon = 1e-5f;
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    if (attrs && attrs->GetAttrNum() > 0) {
        epsilon = *attrs->GetAttrPointer<float>(0);
